/// <summary>
/// This method uded to show are hide the based on enablesmall point.
/// </summary>
/// <returns>ret</returns>
public int active()
{

    int ret = next active();

    FormDataSource InventSum_ds     = this;
    InventSum      InventSumloc     = InventSum_ds.cursor();

    FormControl         KG  = element.design(0).controlName("InventSum_ETGKG");
    FormControl         Mt  = element.design(0).controlName("InventSum_ETGMT");
    FormControl         LBS = element.design(0).controlName("InventSum_ETGLBS");

    if(ETGACFParameters::find().EnableUATSmallPoints == NoYes::Yes)
    {
        KG.visible(true);
        Mt.visible(true);
        LBS.visible(true);
    }
    else
    {
        KG.visible(false);
        Mt.visible(false);
        LBS.visible(false);
    }
    return ret;
}
